operation.add:
// Lets restrict some email providers and domains
$is_bad_email = empty($regOptions['email']) || !filter_var($regOptions['email'], FILTER_VALIDATE_EMAIL) || strlen($regOptions['email']) > 255;

if (!empty($modSettings['enable_restrict_EmailProvider']) && !$is_bad_email)
{
   $email_domain = strtolower(substr(strrchr($regOptions['email'], "@"), 1));

   // 1. Check Restricted Providers
   if (!empty($modSettings['restricted_provider']))
   {
      $restricted_provider = explode(',', strtolower($modSettings['restricted_provider']));
      foreach ($restricted_provider as $provider)
      {
         $provider = trim($provider);
         if (!empty($provider) && stripos($regOptions['email'], $provider) !== false)
            fatal_error(sprintf($txt['restricted'], $regOptions['username']), false);
      }
   }

   // 2. Check Restricted Domains/TLDs
   if (!empty($modSettings['restricted_domain']))
   {
      $restricted_domain = explode(',', strtolower($modSettings['restricted_domain']));
      foreach ($restricted_domain as $domain)
      {
         $domain = trim($domain);
         if (!empty($domain))
         {
            if ($domain[0] !== '.') $domain = '.' . $domain;
            if (substr('.' . $email_domain, -strlen($domain)) === $domain)
               fatal_error(sprintf($txt['restricted_domain_msg'], $regOptions['username']), false);
         }
      }
   }

   // 3. Check Accepted Providers
   if (!empty($modSettings['accepted_provider']))
   {
      $accepted_provider = explode(',', strtolower($modSettings['accepted_provider']));
      $provider_matched = false;
      $has_valid_providers = false;
      foreach ($accepted_provider as $provider)
      {
         $provider = trim($provider);
         if (!empty($provider))
         {
            $has_valid_providers = true;
            if (stripos($regOptions['email'], $provider) !== false)
            {
               $provider_matched = true;
               break;
            }
         }
      }
      if ($has_valid_providers && !$provider_matched)
         fatal_error(sprintf($txt['restricted'], $regOptions['username']), false);
   }

   // 4. Check Accepted Domains/TLDs
   if (!empty($modSettings['accepted_domain']))
   {
      $accepted_domain = explode(',', strtolower($modSettings['accepted_domain']));
      $domain_matched = false;
      $has_valid_domains = false;
      foreach ($accepted_domain as $domain)
      {
         $domain = trim($domain);
         if (!empty($domain))
         {
            $has_valid_domains = true;
            if ($domain[0] !== '.') $domain = '.' . $domain;
            if (substr('.' . $email_domain, -strlen($domain)) === $domain)
            {
               $domain_matched = true;
               break;
            }
         }
      }
      if ($has_valid_domains && !$domain_matched)
         fatal_error(sprintf($txt['restricted_domain_msg'], $regOptions['username']), false);
   }
}

